#include <bits/stdc++.h>
using namespace std;
struct jgt{
	int yw,sx,yy,zf,xh,pm,yszf,ysgf;
}a[20002];
bool cmp(jgt c,jgt d){
	if(c.zf!=d.zf){
		return c.zf>d.zf;
	}
	else if(c.yszf!=d.yszf){
		return c.yszf>d.yszf;
	}
	else{
		return c.ysgf>d.ysgf;
	}
}
bool cmp2(jgt c,jgt d){
	return c.xh<d.xh;
}
int main(){
	int n;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i].yw>>a[i].sx>>a[i].yy;
		a[i].zf=a[i].yw+a[i].sx+a[i].yy;
		a[i].xh=i;
		a[i].yszf=a[i].yw+a[i].sx;
		a[i].ysgf=max(a[i].yw,a[i].sx);
	}
	sort(a+1,a+1+n,cmp);
	a[1].pm=1;
	for(int i=2;i<=n;i++){
		a[i].pm=i;
		if(a[i].zf==a[i-1].zf&&a[i].ysgf==a[i-1].ysgf&&a[i].yszf==a[i-1].yszf){
			a[i].pm=a[i-1].pm;
		}
	}
	sort(a+1,a+n+1,cmp2);
	for(int i=1;i<=n;i++){
		cout<<a[i].pm<<endl;
	}
	return 0;
}
